<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';require_once dirname(__DIR__,2).'/includes/portal_estudiante_aula.php';$portal=portalEstudianteCabecera('Evaluaciones','evaluaciones','Evaluaciones publicadas, fechas de cierre y estado de entrega.');$pdo=obtenerConexion();$contenidos=aulaContenidosEstudiante($pdo,(int)$portal['perfil']['id'],['evaluacion'],200);renderizarListadoContenidosAula($contenidos,'No hay evaluaciones de contenido publicadas.');$q=$pdo->prepare("SELECT e.*,a.nombre capacitacion FROM evaluaciones e JOIN asignaturas a ON a.id=e.asignatura_id WHERE e.estado IN('publicada','cerrada') AND EXISTS(SELECT 1 FROM inscripciones_capacitacion i WHERE i.usuario_id=:u AND i.asignatura_id=e.asignatura_id AND i.estado IN('inscrito','finalizado')) ORDER BY COALESCE(e.fecha_cierre,'9999-12-31'),e.id");$q->execute(['u'=>$portal['perfil']['id']]);$legacy=$q->fetchAll();if($legacy):?><section class="card mt-4"><div class="card-header"><h2 class="h5 mb-0">Evaluaciones registradas por curso</h2></div><div class="card-body"><div class="table-responsive"><table class="table align-middle aula-responsive-table"><thead><tr><th>Evaluación</th><th>Capacitación</th><th>Apertura</th><th>Cierre</th><th>Estado</th></tr></thead><tbody><?php foreach($legacy as$e):?><tr><td data-label="Evaluación"><strong><?=atenea_e($e['titulo'])?></strong><small class="d-block text-muted"><?=atenea_e((string)$e['descripcion'])?></small></td><td data-label="Capacitación"><?=atenea_e($e['capacitacion'])?></td><td data-label="Apertura"><?=atenea_e($e['fecha_apertura']?date('d/m/Y H:i',strtotime($e['fecha_apertura'])):'Por definir')?></td><td data-label="Cierre"><?=atenea_e($e['fecha_cierre']?date('d/m/Y H:i',strtotime($e['fecha_cierre'])):'Por definir')?></td><td data-label="Estado"><span class="badge bg-<?=$e['estado']==='publicada'?'success':'secondary'?>"><?=atenea_e(ucfirst($e['estado']))?></span></td></tr><?php endforeach;?></tbody></table></div></div></section><?php endif;portalEstudiantePie();
